export interface WorkspaceState {
  name: string;
  columns: string[];
  preferences: {
    density: "comfortable" | "compact";
    showHints: boolean;
  };
}

const BASE_WORKSPACE: WorkspaceState = {
  name: "Untitled",
  columns: ["title", "status"],
  preferences: {
    density: "comfortable",
    showHints: true,
  },
};

export function makeDefaultWorkspace(): WorkspaceState {
  return { ...BASE_WORKSPACE };
}

