import assert from "node:assert/strict";
import test from "node:test";

import { WorkspaceSession } from "../src/session.ts";

test("one workspace can be customized and snapshotted", () => {
  const session = new WorkspaceSession();
  session.addColumn("owner");
  session.setDensity("compact");

  assert.deepEqual(session.snapshot(), {
    name: "Untitled",
    columns: ["title", "status", "owner"],
    preferences: { density: "compact", showHints: true },
  });
});
